            <td>${diffPts}</td>
            <td>${diffPct}</td>
            <td>${dirCorr}</td>
            <td>${badge}</td>
            <td style="display:flex;gap:4px;align-items:center">${action}</td>
        </tr>`;
    }).join('');
}

